62: // TestBuild_Single tests that multiple calls to Build() with the same
63: // clients.ServerIdentifier returns the same transport. Also verifies that
64: // only when all references to the newly created transport are released,
65: // the underlying transport is closed.
66: func (s) TestBuild_Single(t *testing.T) {
67: 	ctx, cancel := context.WithTimeout(context.Background(), defaultTestTimeout)
68: 	defer cancel()
69: 
70: 	lis := testutils.NewListenerWrapper(t, nil)
71: 	mgmtServer := e2e.StartManagementServer(t, e2e.ManagementServerOptions{Listener: lis})
72: 
73: 	serverID := clients.ServerIdentifier{
74: 		ServerURI:  mgmtServer.Address,
75: 		Extensions: grpctransport.ServerIdentifierExtension{ConfigName: "local"},
76: 	}
77: 	configs := map[string]grpctransport.Config{
78: 		"local": {Credentials: &testCredentials{transportCredentials: local.NewCredentials()}},
79: 	}
80: 
81: 	// Calling Build() first time should create new gRPC transport.
82: 	builder := grpctransport.NewBuilder(configs)
83: 	tr, err := builder.Build(serverID)
84: 	if err != nil {
85: 		t.Fatalf("Failed to build transport: %v", err)
86: 	}
87: 	// Create a new stream to the server and verify that a new transport is
88: 	// created.
89: 	if _, err = tr.NewStream(ctx, "/envoy.service.discovery.v3.AggregatedDiscoveryService/StreamAggregatedResources"); err != nil {
90: 		t.Fatalf("Failed to create stream: %v", err)
91: 	}
92: 	val, err := lis.NewConnCh.Receive(ctx)
93: 	if err != nil {
94: 		t.Fatalf("Timed out when waiting for a new transport to be created to the management server: %v", err)
95: 	}
96: 	conn := val.(*testutils.ConnWrapper)
97: 
98: 	// Calling Build() again should not create new gRPC transport.
99: 	const count = 9
100: 	transports := make([]clients.Transport, count)
101: 	for i := 0; i < count; i++ {
102: 		func() {
103: 			transports[i], err = builder.Build(serverID)
104: 			if err != nil {
105: 				t.Fatalf("Failed to build transport: %v", err)
106: 			}
107: 			// Create a new stream to the server and verify that no connection
108: 			// is established to the management server at this point. A new
109: 			// transport is created only when an existing connection for
110: 			// serverID does not exist.
111: 			if _, err = tr.NewStream(ctx, "/envoy.service.discovery.v3.AggregatedDiscoveryService/StreamAggregatedResources"); err != nil {
112: 				t.Fatalf("Failed to create stream: %v", err)
113: 			}
114: 			sCtx, sCancel := context.WithTimeout(ctx, defaultTestShortTimeout)
115: 			defer sCancel()
116: 			if _, err := lis.NewConnCh.Receive(sCtx); err != context.DeadlineExceeded {
117: 				t.Fatal("Unexpected new transport created to management server")
118: 			}
119: 		}()
120: 	}
121: 
122: 	// Call Close() multiple times on each of the transport received in the
123: 	// above for loop. Close() calls are idempotent. The underlying gRPC
124: 	// transport is removed after the Close() call but calling close second
125: 	// time should not panic and underlying gRPC transport should not be
126: 	// closed.
127: 	for i := 0; i < count; i++ {
128: 		func() {
129: 			transports[i].Close()
130: 			transports[i].Close()
131: 			sCtx, sCancel := context.WithTimeout(ctx, defaultTestShortTimeout)
132: 			defer sCancel()
133: 			if _, err := conn.CloseCh.Receive(sCtx); err != context.DeadlineExceeded {
134: 				t.Fatal("Unexpected transport closure to management server")
135: 			}
136: 		}()
137: 	}
138: 
139: 	// Call the last Close(). The underlying gRPC transport should be closed
140: 	// because calls in the above for loop have released all references.
141: 	tr.Close()
142: 	if _, err := conn.CloseCh.Receive(ctx); err != nil {
143: 		t.Fatal("Timeout when waiting for connection to management server to be closed")
144: 	}
145: 
146: 	// Calling Build() again, after the previous transport was actually closed,
147: 	// should create a new one.
148: 	tr2, err := builder.Build(serverID)
149: 	if err != nil {
150: 		t.Fatalf("Failed to create xDS client: %v", err)
151: 	}
152: 	defer tr2.Close()
153: 	// Create a new stream to the server and verify that a new transport is
154: 	// created.
155: 	if _, err = tr2.NewStream(ctx, "/envoy.service.discovery.v3.AggregatedDiscoveryService/StreamAggregatedResources"); err != nil {
156: 		t.Fatalf("Failed to create stream: %v", err)
157: 	}
158: 	if _, err := lis.NewConnCh.Receive(ctx); err != nil {
159: 		t.Fatalf("Timed out when waiting for a new transport to be created to the management server: %v", err)
160: 	}
161: }
